#include <iostream>
#include <string>

enum Light
{
    red,    // 0
    yellow, // 1
    green   // 2
};

Light parseLight(const std::string& name)
{
    if (name == "red")
        return red;
    if (name == "yellow")
        return yellow;
    return green;
}

std::string lightName(Light l)
{
    switch (l)
    {
        case red:    return "red";
        case yellow: return "yellow";
        case green:  return "green";
        default:     return "unknown";
    }
}

Light nextLight(Light l)
{
    switch (l)
    {
        case red:    return green;
        case green:  return yellow;
        case yellow: return red;
        default:     return l;
    }
}

int main()
{
    std::string name{};
    std::cin >> name;

    Light current{ parseLight(name) };
    std::cout << lightName(current) << '\n';
    std::cout << lightName(nextLight(current)) << '\n';

    return 0;
}

